>> It appears that at the very least, the problem is 
>> that the autokey context vnet is never initialized.

Yes, my quick (and dirty :-) patch is:

Index: sys/netinet/tcp_fastopen.c
===================================================================
--- sys/netinet/tcp_fastopen.c	(revision 312971)
+++ sys/netinet/tcp_fastopen.c	(working copy)
@@ -104,6 +104,7 @@
 #include "opt_inet.h"

 #include <sys/param.h>
+#include <sys/jail.h>
 #include <sys/kernel.h>
 #include <sys/limits.h>
 #include <sys/lock.h>
@@ -266,7 +267,7 @@
 {
 	struct tcp_fastopen_callout *ctx = arg;

-	CURVNET_SET(ctx->v);
+	CURVNET_SET(TD_TO_VNET(curthread));
 	tcp_fastopen_autokey_locked();
 	callout_reset(&ctx->c, V_tcp_fastopen_autokey * hz,
 		      tcp_fastopen_autokey_callout, ctx);


